import React, { useState, useEffect } from "react";
import axios from "axios";
import IconSelect from "../TechnoAdmin/IconSelect";
import "./Technos.css";

const API = "http://localhost:5064/api";

interface Technos {
    technologieId: number;
    nom: string;
    iconePath: string;
}

export default function TechnologiesAdmin() {
    const [technos, setTechnos] = useState<Technos[]>([]);
    const [newTechno, setNewTechno] = useState({ nom: "", iconePath: "" });
    const [selectedIcon, setSelectedIcon] = useState<string>("");

    useEffect(() => {
        fetchTechnos().catch();
    }, []);

    const fetchTechnos = async () => {
        try {
            const response = await axios.get<Technos[]>(`${API}/technologies`);
            setTechnos(response.data);
        } catch (error) {
            console.log(error);
        }
    };

    const handleDelete = async (id: number) => {
        try {
            await axios.delete(`${API}/technologies/${id}`);
            setTechnos(technos.filter((techno) => techno.technologieId !== id));
        } catch (error) {
            console.log(error);
        }
    };

    const handleAdd = async () => {
        if (newTechno.nom && selectedIcon) {
            try {
                const response = await axios.post(`${API}/technologies`, {
                    nom: newTechno.nom,
                    iconePath: selectedIcon,
                });
                setTechnos([...technos, response.data]);
                setNewTechno({ nom: "", iconePath: "" });
                setSelectedIcon("");
            } catch (error) {
                console.log(error);
            }
        }
    };

    const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        setNewTechno({ ...newTechno, [e.target.name]: e.target.value });
    };

    return (
        <div className="TechnoAdminContainer">
            <h2>Gestion des Technologies</h2>

            <div className="AddTechnoForm">
                <input
                    type="text"
                    name="nom"
                    placeholder="Nom de la technologie"
                    value={newTechno.nom}
                    onChange={handleChange}
                />
                <IconSelect value={selectedIcon} onChange={setSelectedIcon} />
                <button onClick={handleAdd}>Ajouter</button>
            </div>

            <ul className="TechnoList">
                {technos.map((techno) => (
                    <li key={techno.technologieId} className="TechnoItem">
                        <img src={techno.iconePath} alt={techno.nom} className="TechnoIcon" />
                        <span>{techno.nom}</span>
                        <button onClick={() => handleDelete(techno.technologieId)}>Supprimer</button>
                    </li>
                ))}
            </ul>
        </div>
    );
}
